```class Solution {
    public int[] gardenNoAdj(int n, int[][] paths) {
        List<Integer>[] graph = new List[n + 1];
        for (int i = 1; i <= n; i++) {
            graph[i] = new ArrayList<>();
        }
        for (int[] path : paths) {
            graph[path[0]].add(path[1]);
            graph[path[1]].add(path[0]);
        }
        int[] ans = new int[n];
        for (int i = 1; i <= n; i++) {
            int flower = 1;
            for (int neighbor : graph[i]) {
                flower = (flower + 1) % 4;
            }
            ans[i - 1] = flower;
        }
        return ans;
    }
}```
